import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Sanitize user input using OWASP Java Encoder
            String safeUserInput = Encode.forHtml(userInput);

            // Use sanitized input in the greeting message
            String greetingMessage = "Hello, " + safeUserInput + "!";

            System.out.println(greetingMessage);
        } catch (IOException e) {
            System.err.println("An error occurred while reading user input.");
        }
    }
}

